<template>
    <BaseModal
        name="options"
        :mobileMode="true"
        :closeOutside="true"
        :isLoading="data.loading"
    >
        <template v-slot:title>
            <div class="title">
                <span>{{ data.title }}</span>
            </div>
        </template>
        <template v-slot:content>
            <ul class="kebab-list">
                <li v-for="(item, id) in data.options" :key="id" class="clickable" @click="choose(item)">
                    <Icon v-if="item.icon" :icon="item.icon"/>
                    <span>{{ item.name }}</span>
                </li>
            </ul>
        </template>
    </BaseModal>
</template>

<script setup>
import { onMounted, reactive } from 'vue';
import { useI18n } from 'vue-i18n';

import BaseModal from '🔗/components/modals/BaseModal.vue';
import stores from '@/stores';

// import api from '🔗/api';
import { message } from '🔗/utils/utils';

const { t } = useI18n();

const modals = stores.modals();

const data = reactive({
    loading: true,
    title: '',
    options: []
});


const choose = (payload) => {
    close(payload?.code);
}

const close = (code) => {
    modals.close('options', code);
};


onMounted(async () => {
    const payload = modals.getData('options');

    if (!payload?.options?.length) {
        close();
        return;
    }

    data.options = payload.options;
    data.title = payload.title;

    data.loading = false;
});

</script>

<style lang="scss" scoped>
    .title {
        display: flex;
        width: 100%;
        align-items: center;
        gap: 24px;
        flex-direction: column;
        padding-top: 12px;
    }

    ul.kebab-list {
        @include settings-list;
        margin-top: 24px;
    }
</style>
